import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    if not unvisited_customers:
        return None

    # Initialize scores and best node choice
    best_score = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        # Calculate travel info and penalties
        travel_distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = travel_distance / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        # Time penalties
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        elif arrival_time > end_window:
            wait_time = (arrival_time - end_window) * 10
        else:
            wait_time = 0

        # Scoring based on distance and waiting time
        score = travel_time + wait_time

        # Consider historical performance (previous truck visitations closer to this customer)
        historical_score = 0
        for truck_pos in all_truck_pos:
            if truck_pos is not cur_truck_pos:
                historical_score += np.log(1 + calculate_distance(truck_pos, customer_pos))

        total_score = score - 0.1 * historical_score  # Apply a small weighting to the historical score

        if total_score < best_score:
            best_score = total_score
            best_node = i

    return best_node

