def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def logistic_cost_penalty(arrival, start, end):
        if arrival < start:
            return 50 * (1 / (1 + np.exp(-(start - arrival) / 10))) - 25
        elif arrival > end:
            return 50 * (1 / (1 + np.exp(-(arrival - end) / 10))) - 25
        else:
            return 0

    def distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    if len(unvisited_customers) == 0:
        return None

    scores = []
    for i, customer in enumerate(unvisited_customers):
        travel_time = distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        start, end = time_windows[i]
        score = travel_time + logistic_cost_penalty(arrival_time, start, end)
        scores.append((score, i))

    best_score, best_node = min(scores)

    return best_node

