def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(point_a, point_b):
        return np.linalg.norm(point_a - point_b)

    def get_traffic_delay(from_pos, to_pos):
        # Simplified traffic model: delay increases with distance and traffic factor (imaginary)
        traffic_factor = 1.5
        return (distance(from_pos, to_pos) / 100) * traffic_factor

    if not unvisited_customers:
        return None

    min_cost = float('inf')
    best_node = None

    for index, customer_pos in enumerate(unvisited_customers):
        travel_distance = distance(cur_truck_pos, customer_pos)
        travel_time = travel_distance / truck_speed

        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[index]

        traffic_delay = get_traffic_delay(cur_truck_pos, customer_pos)
        adjusted_arrival_time = arrival_time + traffic_delay

        if adjusted_arrival_time < start_time:
            time_penalty = (start_time - adjusted_arrival_time) * 1.5
        elif adjusted_arrival_time > end_time:
            time_penalty = (adjusted_arrival_time - end_time) * 2
        else:
            time_penalty = 0

        cost = travel_time + time_penalty

        if cost < min_cost:
            min_cost = cost
            best_node = index

    return best_node
